function normalize(s: string): string {
  return s
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9 ]+/g, '')
    .replace(/\s+/g, ' ');
}

// Levenshtein-light: count common letters by 3-grams for fuzzy fallback.
function trigrams(s: string): Set<string> {
  const out = new Set<string>();
  const t = '  ' + s + '  ';
  for (let i = 0; i < t.length - 2; i++) out.add(t.slice(i, i + 3));
  return out;
}

function jaccard(a: Set<string>, b: Set<string>): number {
  let inter = 0;
  for (const t of a) if (b.has(t)) inter++;
  return inter / (a.size + b.size - inter || 1);
}

const KEY_TRIGRAMS: Record<string, Set<string>> = {};
for (const k of FOOD_KEYS) KEY_TRIGRAMS[k] = trigrams(k.replace(/-/g, ' '));

/** Find the best matching food image for an arbitrary user input. */
export function resolveFood(input: string): { key: string; image: any } {
  const n = normalize(input || '');
  if (!n) return { key: 'burger', image: FOOD_REGISTRY['burger'] };

  // 1) alias direct hit
  if (ALIASES[n]) {
    const k = ALIASES[n];
    return { key: k, image: FOOD_REGISTRY[k] };
  }

  // 2) exact registry key (with hyphens) or single-word substring on alias
  if (FOOD_REGISTRY[n]) return { key: n, image: FOOD_REGISTRY[n] };
  const dashed = n.replace(/ /g, '-');
  if (FOOD_REGISTRY[dashed]) return { key: dashed, image: FOOD_REGISTRY[dashed] };

  // 3) partial alias match (input contains alias word)
  for (const a of Object.keys(ALIASES)) {
    if (n === a || n.includes(a) || a.includes(n)) {
      const k = ALIASES[a];
      return { key: k, image: FOOD_REGISTRY[k] };
    }
  }

  // 4) registry key substring
  for (const k of FOOD_KEYS) {
    const flat = k.replace(/-/g, ' ');
    if (n.includes(flat) || flat.includes(n)) return { key: k, image: FOOD_REGISTRY[k] };
  }

  // 5) fuzzy trigram similarity
  const inTris = trigrams(n);
  let bestKey = 'burger';
  let bestScore = 0;
  for (const k of FOOD_KEYS) {
    const s = jaccard(inTris, KEY_TRIGRAMS[k]);
    if (s > bestScore) {
      bestScore = s;
      bestKey = k;
    }
  }
  return { key: bestKey, image: FOOD_REGISTRY[bestKey] };
}

